#include <stdio.h>
int main() {
    int n, t;
    scanf("%d %d", &n, &t);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int time = 0;
    for (int i = 0; i < n; i++) {
        time += arr[i] * 2;
    }
    printf("%d\n", time);
    return 0;
}

