public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int t = scanner.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = scanner.nextInt();
        }
        int time = 0;
        for (int i = 0; i < n; i++) {
            time += arr[i] * 2;
        }
        System.out.println(time);
    }
