const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', (line) => {
    input.push(line);
});
rl.on('close', () => {
    let [n, t] = input[0].split(' ').map(Number);
    let arr = input[1].split(' ').map(Number);
    let time = 0;
    for (let i = 0; i < n; i++) {
        time += arr[i] * 2;
    }
    console.log(time);
});

